#include <bits/stdc++.h>
using namespace std;

using ll = long long;
const ll INF = LLONG_MAX;
const int MAXN = 100005;

vector<pair<int,int>> graph[MAXN];
ll dista[MAXN];
int src[MAXN];

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);

    int N, M, K;
    cin >> N >> M >> K;

    priority_queue<
        pair<ll,int>,
        vector<pair<ll,int>>,
        greater<pair<ll,int>>
    > pq;

    for (int i = 1; i <= N; i++) {
        dista[i] = INF;
        src[i] = 0;
    }

    vector<int> out(K);
    for (int i = 0; i < K; i++) {
        cin >> out[i];
        dista[out[i]] = 0;
        src[out[i]] = out[i];
        pq.push({0, out[i]});
    }

    for (int i = 0; i < M; i++) {
        int x, y, z;
        cin >> x >> y >> z;

        graph[x].push_back({y, z});
        graph[y].push_back({x, z});
    }

    ll ans = INF;

    while (!pq.empty()) {

        auto [d, u] = pq.top();
        pq.pop();

        if (d != dista[u]) continue;

        for (auto [v, w] : graph[u]) {

            ll nd = d + w;

            if (dista[v] == INF) {
                dista[v] = nd;
                src[v] = src[u];
                pq.push({nd, v});
            }

            else if (src[v] != src[u]) {
                ans = min(ans, dista[v] + nd);
            }
        }
    }

    cout << ans << "\n";
}

