#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

#define MAXN 100005
#define MAXM 600005

typedef long long ll;

typedef struct {
    int to;
    int w;
    int next;
} Edge;

typedef struct {
    ll dist;
    int node;
} State;

Edge edges[MAXM];
int head[MAXN];
int edge_cnt = 0;

ll dist[MAXN];
int src[MAXN];

State heap[MAXM];
int heap_size = 0;

int N, M, K;

void add_edge(int u,int v,int w){
    edges[edge_cnt].to=v;
    edges[edge_cnt].w=w;
    edges[edge_cnt].next=head[u];
    head[u]=edge_cnt++;
}

void push(State s){
    heap[++heap_size]=s;
    int i=heap_size;

    while(i>1 && heap[i].dist<heap[i/2].dist){
        State t=heap[i];
        heap[i]=heap[i/2];
        heap[i/2]=t;
        i/=2;
    }
}

State pop(){
    State ret=heap[1];
    heap[1]=heap[heap_size--];

    int i=1;

    while(1){
        int l=2*i,r=2*i+1,small=i;

        if(l<=heap_size && heap[l].dist<heap[small].dist) small=l;
        if(r<=heap_size && heap[r].dist<heap[small].dist) small=r;

        if(small==i) break;

        State t=heap[i];
        heap[i]=heap[small];
        heap[small]=t;

        i=small;
    }

    return ret;
}

int empty(){
    return heap_size==0;
}

int main(){

    scanf("%d %d %d",&N,&M,&K);

    for(int i=1;i<=N;i++){
        head[i]=-1;
        dist[i]=LLONG_MAX;
        src[i]=0;
    }

    int out[K];

    for(int i=0;i<K;i++){
        scanf("%d",&out[i]);
        dist[out[i]]=0;
        src[out[i]]=out[i];
        push((State){0,out[i]});
    }

    for(int i=0;i<M;i++){
        int x,y,z;
        scanf("%d %d %d",&x,&y,&z);
        add_edge(x,y,z);
        add_edge(y,x,z);
    }

    ll ans=LLONG_MAX;

    while(!empty()){

        State cur=pop();
        ll d=cur.dist;
        int u=cur.node;

        if(d!=dist[u]) continue;

        for(int e=head[u];e!=-1;e=edges[e].next){

            int v=edges[e].to;
            ll nd=d+edges[e].w;

            if(dist[v]==LLONG_MAX){
                dist[v]=nd;
                src[v]=src[u];
                push((State){nd,v});
            }

            else if(src[v]!=src[u]){
                ll cand=dist[v]+nd;
                if(cand<ans) ans=cand;
            }
        }
    }

    printf("%lld\n",ans);
}

